export interface TopoNode {
  id: string;
  deps: string[];
}

export class CycleError extends Error {
  readonly cycle: string[];
  constructor(cycle: string[]) {
    super(`cycle detected: ${cycle.join(" -> ")}`);
    this.name = "CycleError";
    this.cycle = cycle;
  }
}

export function topoSort(nodes: TopoNode[]): string[] {
  const byId = new Map(nodes.map((n) => [n.id, n]));
  const status = new Map<string, "visiting" | "done">();
  const result: string[] = [];
  const stack: string[] = [];
  const visit = (id: string): void => {
    const s = status.get(id);
    if (s === "done") return;
    if (s === "visiting") {
      const idx = stack.indexOf(id);
      throw new CycleError(stack.slice(idx).concat(id));
    }
    status.set(id, "visiting");
    stack.push(id);
    const node = byId.get(id);
    if (node) {
      for (const dep of node.deps) visit(dep);
    }
    stack.pop();
    status.set(id, "done");
    result.push(id);
  };
  for (const node of nodes) visit(node.id);
  return result;
}
